import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: {(project_basename, framework, package_id): resolved_version}
def build_lookup(data):
    lookup = {}
    for proj in data['projects']:
        pname = proj['path'].rsplit('/', 1)[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                lookup[(pname, fw['framework'], pkg['id'])] = pkg['resolvedVersion']
    return lookup

b = build_lookup(baseline)
a = build_lookup(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))

changes = []
unchanged = []
for key in all_keys:
    pname, fw, pkg_id = key
    bv = b.get(key, 'N/A')
    av = a.get(key, 'N/A')
    if bv != av:
        changes.append((pname, fw, pkg_id, bv, av))
    else:
        unchanged.append((pname, fw, pkg_id, bv))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'{c[0]} ({c[1]}): {c[2]}  {c[3]} -> {c[4]}')
else:
    print('None')

print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'{u[0]} ({u[1]}): {u[2]}  {u[3]}')
"

